  "type": "string",
  "enum": [
   "pass",
   "redact"
  ],
  "default": "pass",
  "description": "Strategy applied to fields not matched by any rule."
 }
}

{
 "field_rule": {
  "type": "object",
  "required": [
   "path",
   "sensitivity",
   "strategy"
  ],
  "additionalProperties": false,
  "properties": {
   "path": {
    "type": "string",
    "description": "Dot-delimited path into the LogEvent dict (e.g. 'data.user_id', 'source', 'data.email'). Supports '*' as a single-level wildcard and '**' as a recursive wildcard."
   },
   "sensitivity": {
    "type": "string",
    "enum": [
     "public",
     "internal",
     "confidential",
     "restricted"
    ],
    "description": "Data classification level. public = no masking needed, internal = organisation-visible, confidential = role-gated, restricted = PII / secrets."
   },
   "strategy": {
    "type": "string",
    "enum": [
     "pass",
     "sha256_hash",
     "hmac_pseudonym",
     "redact",
     "truncate"
    ],
    "description": "Transformation applied before the event reaches subscribers."
   },
   "truncate_length": {
    "type": "integer",
    "minimum": 1,
    "description": "Required when strategy is 'truncate'. Number of leading characters to keep."
   },
   "description": {
    "type": "string",
    "description": "Human-readable justification for this rule."
   }
  },
  "if": {
   "properties": {
    "strategy": {
     "const": "truncate"
    }
   }
  },
  "then": {
   "required": [
    "truncate_length"
   ]
  }
 }
}

