{
 "term": "commitment_record",
 "definition": "A hash-chained ledger entry recording a policy decision, activation, session lifecycle event, or permission change.  CommitmentRecords are append-only and form the backbone of the Lumina audit trail.",
 "aliases": [
  "commitment",
  "policy commitment"
 ],
 "related_terms": [
  "system_logs",
  "trace_event"
 ],
 "example_in_context": "When a Domain Authority activates a new domain-physics version, the runtime writes a commitment_record of type domain_physics_activation to the system log."
}

{
 "term": "trace_event",
 "definition": "A hash-chained ledger entry logged after each orchestrator turn.  It carries provenance hashes — domain_physics_hash, system_physics_hash, prompt_contract_hash — enabling full turn-level auditability.",
 "aliases": [
  "trace",
  "ctl event"
 ],
 "related_terms": [
  "system_logs",
  "commitment_record"
 ],
 "example_in_context": "Every time the orchestrator completes a turn it appends a trace_event to the domain System Log that includes the SHA-256 of the active system-physics.json."
}

{
 "term": "escalation_record",
 "definition": "A hash-chained ledger entry created when the orchestrator cannot resolve a situation within its authorised action space and must defer to a human Meta Authority.",
 "aliases": [
  "escalation"
 ],
 "related_terms": [
  "escalation_trigger",
  "meta_authority",
  "system_logs"
 ],
 "example_in_context": "If all standing-order attempts are exhausted, an escalation_record is appended to the System Logs and a human Meta Authority is notified."
}

{
 "term": "domain_physics",
 "definition": "The machine-readable policy layer authored by a Domain Authority for a specific domain module.  Defines standing orders, invariants, escalation triggers, glossary, and tool adapters in scope for that domain.",
 "aliases": [
  "domain physics"
 ],
 "related_terms": [
  "system_physics",
  "domain_pack",
  "domain_authority"
 ],
