}

{
 "term": "prompt_contract",
 "definition": "The assembled, layered input packet sent to the LLM at each orchestrator turn.  Built from: Global Base Prompt + Domain Physics + Module State + NLP anchors.  The LLM is constrained to this contract.",
 "aliases": [
  "prompt contract",
  "prompt packet"
 ],
 "related_terms": [
  "orchestrator",
  "tool_adapter"
 ],
