}

{
 "term": "standing_order",
 "definition": "A bounded, pre-authorised automated response the orchestrator takes when a specific invariant is violated.  Standing orders have a max_attempts limit; exhaustion triggers escalation.",
 "aliases": [
  "standing order"
 ],
 "related_terms": [
  "invariant",
  "escalation_trigger"
 ],
