{
 "id": "exponent_rules",
 "name": "Exponent Rules",
 "unit": "5 — Exponents & Polynomials",
 "description": "The student can apply product, power, quotient, and negative exponent rules to simplify combined expressions. Law 4 numeric entry point: each rule transforms the expression's shape while preserving its value.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "structure_preserved",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_exponent_rules_v1",
  "task_description": "Simplify: (x²)³ · x⁻¹ / x⁴.\nShow each exponent rule as a separate step and name the rule (product, power, quotient, or negative exponent) beside each step. Write the final answer with a positive exponent.\n",
  "sensor_purpose": "Four exponent rules must be applied sequentially. The canonical Law 4 failure: (x²)³ = x⁵ (adding instead of multiplying exponents — wrong shape change). The rule-naming requirement ensures the student is categorising transformations, not pattern-matching. Naming a rule incorrectly while applying it correctly signals execution without structural understanding.\n",
  "grading": [
   {
    "check": "structure_preserved",
    "weight": 0.5
   },
   {
    "check": "correct_final_value",
    "weight": 0.35
   },
   {
    "check": "step_count >= 3",
    "weight": 0.15
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

{
 "id": "polynomial_operations",
 "name": "Polynomial Operations — Expansion",
 "unit": "5 — Exponents & Polynomials",
 "description": "The student can multiply two binomials using FOIL, listing all four partial products before collecting like terms, and can add and subtract polynomials by combining only like-degree terms. Law 4 assembly.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "structure_preserved",
  "equivalence_preserved",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_polynomial_operations_v1",
  "task_description": "Expand (x + 3)(x − 5) using FOIL.\n(a) List all four partial products (First, Outer, Inner, Last) on separate lines before collecting like terms.\n(b) Collect like terms and write the simplified polynomial.\n(c) Verify that x = 5 is a root of your simplified polynomial by substituting it and checking the result equals zero.\n",
  "sensor_purpose": "Part (a) makes all four partial products visible. The canonical Law 4 assembly failure: a missing partial product (usually Outer or Inner), collapsing (x+3)(x−5) to x²−15 instead of x²−2x−15. Part (c) activates Law 3 simultaneously: x = 5 is easily checked via the factored form (5+3)(5−5) = 0, confirming the expanded and factored forms are the same object.\n",
  "grading": [
   {
    "check": "structure_preserved",
    "weight": 0.45
   },
   {
    "check": "equivalence_preserved",
    "weight": 0.3
   },
   {
    "check": "verify_solution_substitution",
    "weight": 0.25
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

{
 "id": "factoring_quadratics",
 "name": "Factoring Quadratics",
 "unit": "5 — Exponents & Polynomials",
 "description": "The student can factor a monic quadratic x² + bx + c into (x + p)(x + q) by finding the correct factor pair, and must verify by expanding back to the original. The Law 4 disassembly artifact — the hardest structural diagnostic in the curriculum.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "structure_preserved",
  "equivalence_preserved",
  "substitution_valid",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_factoring_quadratics_v1",
  "task_description": "Factor x² + 5x + 6.\n(a) Find the two integers p and q such that p·q = 6 and p + q = 5. Show your factor pairs considered.\n(b) Write the factored form.\n(c) Verify by expanding your factored form using FOIL back to the original polynomial. Show all four partial products.\n(d) State the two roots of x² + 5x + 6 = 0.\n",
  "sensor_purpose": "The canonical Law 4 disassembly sensor. A wrong answer in (b) is always exposed in (c): the FOIL will not reproduce x² + 5x + 6. The student cannot pass (c) without correcting (b). Part (d) activates Law 3: the roots must satisfy the original expression — the factored form IS the original, so setting each factor to zero gives the roots. Students who treat (d) as disconnected from (a)–(c) have not grasped interchangeability.\n",
  "grading": [
