{
 "id": "variables_and_expressions",
 "name": "Variables & Expressions — Introduction",
 "unit": "1 — Foundations",
 "description": "The student can evaluate algebraic expressions by substituting known values for variables and applying arithmetic operations in the correct order. Foundation for understanding that variables are placeholders.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "equivalence_preserved",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_variables_expressions_v1",
  "task_description": "Evaluate 3(x + 4y) − 2z given x = 2, y = 1, z = 3. Show each substitution step and every arithmetic operation separately.\n",
  "sensor_purpose": "Tests whether the student treats the expression as a balanced structure (Law 1 introduction): substituting x=2 correctly means the expression retains its value. Distributing 3 across (x + 4y) before substituting is the canonical shortcut error that reveals incomplete structural understanding.\n",
  "grading": [
   {
    "check": "correct_final_value",
    "weight": 0.5
   },
   {
    "check": "substitution_shown",
    "weight": 0.3
   },
   {
    "check": "step_count >= 2",
    "weight": 0.2
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

{
 "id": "order_of_operations",
 "name": "Order of Operations — PEMDAS",
 "unit": "1 — Foundations",
 "description": "The student can evaluate complex arithmetic and algebraic expressions by applying PEMDAS correctly: Parentheses, Exponents, Multiplication and Division (left to right), Addition and Subtraction (left to right). This is the prerequisite for Law 2 — students must know the order before they can reverse it.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "reversibility_order_correct",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_order_of_operations_v1",
  "task_description": "Simplify: 4 + 3 × (8 − 2)² ÷ 9. Show each operation on a separate line in the order you perform it.\n",
  "sensor_purpose": "Forces exponents before multiplication — the exact order that must later be reversed when isolating variables. A student who adds 3 × before computing (8 − 2)² has not yet internalized the order that Law 2 requires them to undo. This equation has exactly one correct step sequence.\n",
  "grading": [
   {
    "check": "correct_final_value",
    "weight": 0.5
   },
   {
    "check": "exponents_before_multiply",
    "weight": 0.3
   },
   {
    "check": "step_count >= 3",
    "weight": 0.2
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

{
 "id": "single_step_equations",
 "name": "Single-Step Linear Equations",
 "unit": "2 — Linear Equations & Inequalities",
 "description": "The student can solve single-step equations of the form x + a = b and ax = b using one inverse operation, showing that operation applied to both sides of the equation, and verifying the solution by substitution.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "equivalence_preserved",
  "reversibility_order_correct",
  "solution_verifies",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_single_step_equations_v1",
  "task_description": "Solve 7x = 84. Show the inverse operation applied to both sides, state your answer, and verify by substituting back into the original equation.\n",
  "sensor_purpose": "Simultaneously tests Law 1 (both sides get the same division) and the entry level of Law 2 (identifying multiplication as the operation to undo). A student who just writes \"x = 12\" without showing the division step has passed arithmetic but not algebraic procedure.\n",
  "grading": [
   {
    "check": "equivalence_preserved",
    "weight": 0.4
   },
   {
    "check": "verify_solution_substitution",
    "weight": 0.4
   },
   {
    "check": "step_count >= 2",
    "weight": 0.2
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

{
 "id": "multi_step_linear_equations",
 "name": "Multi-Step Linear Equations",
 "unit": "2 — Linear Equations & Inequalities",
 "description": "The student can solve two-step equations of the form ax + b = c and ax − b = c by applying inverse operations in the correct reversed-PEMDAS order, showing each step applied to both sides, and verifying the solution. This is the primary Law 2 diagnostic artifact in this module.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "equivalence_preserved",
  "reversibility_order_correct",
  "solution_verifies",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_multi_step_linear_v1",
  "task_description": "Solve 3x − 7 = 14. Show each inverse operation applied to both sides in the correct order, state your answer, and verify by substitution.\n",
  "sensor_purpose": "The canonical Law 2 diagnostic: does the student add 7 to both sides first (correct — undoing subtraction before undoing multiplication), or divide by 3 first (reversed-order failure)? The two-step structure of this equation makes the order of operations non-negotiable. Their work-steps reveal the answer without any explicit question about the law.\n",
  "grading": [
   {
    "check": "equivalence_preserved",
    "weight": 0.35
   },
   {
    "check": "reversibility_order_correct",
    "weight": 0.3
   },
   {
    "check": "verify_solution_substitution",
    "weight": 0.25
   },
   {
    "check": "step_count >= 3",
    "weight": 0.1
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

{
 "id": "linear_inequalities",
 "name": "Linear Inequalities & the Direction-Flip Rule",
 "unit": "2 — Linear Equations & Inequalities",
 "description": "The student can solve linear inequalities including cases requiring the direction-flip rule when multiplying or dividing by a negative number, state the solution as an inequality, and describe the solution set on a number line.\n",
 "unlock_condition": "mastery >= 0.8 on all required skills, confirmed by boss challenge",
 "mastery_threshold": 0.8,
 "skills_required": [
  "equivalence_preserved",
  "reversibility_order_correct",
  "inequality_direction_preserved",
  "solution_verifies",
  "show_work_minimum"
 ],
 "boss_challenge": {
  "id": "boss_linear_inequalities_v1",
  "task_description": "Solve −4x + 3 > −9. Show each step applied to both sides, flip the inequality sign at the correct moment, state your final answer as an inequality, and describe whether you would shade left or right on the number line.\n",
  "sensor_purpose": "The negative coefficient on x forces the direction-flip signal. A student who correctly isolates −4x > −12 but then writes x > 3 (wrong direction) has provided an unambiguous Law 2 direction-flip failure. The number line question confirms whether they understand the solution is a set, not a single value — distinguishing inequality reasoning from equation solving.\n",
  "grading": [
   {
    "check": "equivalence_preserved",
    "weight": 0.25
   },
   {
    "check": "inequality_direction_correct",
    "weight": 0.4
   },
   {
    "check": "verify_inequality_solution",
    "weight": 0.25
   },
   {
    "check": "step_count >= 3",
    "weight": 0.1
   }
  ],
  "pass_threshold": 0.8,
  "hints_allowed": false,
  "max_attempts_per_session": 1
 }
}

