{
 "term": "ctl",
 "definition": "System Logs — the append-only, hash-chained record of all domain-session trace events and commitment records."
}

{
 "term": "commitment_record",
 "definition": "A System Log record that marks a durable system decision: domain-physics activation, role change, escalation, or night-cycle outcome."
}

{
 "term": "trace_event",
 "definition": "A single LLM-driven turn record in the System Logs, capturing input evidence, state delta, and the system-physics hash active at the time."
}

{
 "term": "system_physics",
 "definition": "The machine-readable global invariant layer (cfg/system-physics.yaml / .json) that constrains every domain session regardless of which domain is active."
}

{
 "term": "domain_physics",
 "definition": "A domain-pack JSON file defining the module's topics, glossary, standing orders, escalation conditions, and artifacts."
}

{
 "term": "domain_pack",
 "definition": "A self-contained module bundle (cfg, prompts, domain-lib, controllers, modules) that implants a domain into the Lumina runtime."
}

{
 "term": "domain_authority",
 "definition": "A role with authoring rights over one or more governed modules; highest ceiling for domain-scoped operations."
}

{
 "term": "meta_authority",
 "definition": "The cross-domain governance layer above a Domain Authority; approves cross-domain synthesis and standing-order conflicts."
}

{
 "term": "policy_gate",
 "definition": "A hard invariant in system physics that cannot be overridden by any domain pack; violated by a session → escalation."
}

{
 "term": "hash_chain",
 "definition": "The linked sequence of record_hash values in the System Logs that provides tamper-evidence across all ledger entries."
}

{
 "term": "rbac",
 "definition": "Role-Based Access Control — Lumina's permission model combining chmod-style octal modes with optional extended ACLs."
}

{
 "term": "domain_registry",
 "definition": "cfg/domain-registry.yaml — the file that maps domain_id keys to their runtime-config paths and routing metadata."
}

{
 "term": "standing_order",
 "definition": "A persistent instruction authored by a Domain Authority that survives across session turns until explicitly revoked."
}

{
 "term": "escalation",
 "definition": "A domain-session signal that exceeds a policy-gate threshold; surfaces to Meta Authority and writes an escalation record to the System Logs."
}

{
 "term": "night_cycle",
 "definition": "A configurable off-hours batch pass that performs glossary expansion, constraint refresh, and knowledge-graph rebuilds for a domain."
}

{
 "term": "tool_adapter",
 "definition": "A domain-pack module that exposes a callable to the Lumina orchestrator as a named tool during a session."
}

{
 "term": "domain_lib",
 "definition": "A domain-pack library of pure functions available to controller adapters without LLM involvement."
}

{
 "term": "pseudonymous_id",
 "definition": "The opaque, non-reversible identifier stored in the System Logs in place of a real user identifier."
}

{
 "term": "ingestion_pipeline",
 "definition": "The upload → extract → SLM-interpret → DA-review → commit workflow for importing external content into a domain pack."
}

{
 "term": "governed_modules",
 "definition": "The list of module IDs (e.g. domain/edu/algebra-level-1/v1) that a domain_authority has authoring and approval rights over.  Required at invite time; cannot be empty for the domain_authority role."
}

{
 "term": "invite_token",
 "definition": "A single-use, URL-safe token generated when an admin invites a new user.  Embedded in the setup_url; consumed by POST /api/auth/setup-password to activate the account.  Expires after LUMINA_INVITE_TOKEN_TTL_SECONDS (default 24 h)."
}

{
 "term": "pending_user",
 "definition": "A user account that has been created by invitation but not yet activated.  active=false, password_hash is empty.  Cannot log in until POST /api/auth/setup-password is called with a valid invite_token."
}

{
 "term": "user_management_sop",
 "definition": "The standing order defining the invite → setup-link → password-set → active account workflow.  Ensures passwords are never transmitted over the admin interface."
}

{
 "term": "domain_authority_onboarding_sop",
 "definition": "The standing order for creating domain_authority accounts with explicit governed_modules definitions before the invite is issued."
}

{
 "term": "escalation_review_sop",
 "definition": "The standing order for reviewing, resolving, and optionally PIN-unlocking sessions tied to open escalation events."
}

{
 "term": "domain_role",
 "definition": "A role defined in a module's domain-physics.json (e.g. student, teacher, parent) that is scoped to that domain.  Domain roles are not system roles; they map to the system role 'user' via maps_to_system_role.  Domain roles carry module-specific capabilities and access levels."
}

{
 "term": "system_role",
 "definition": "One of the seven RBAC roles recognised by the Lumina kernel: root, domain_authority, it_support, qa, auditor, user, guest.  System roles are stored in the user record and govern API-level access.  Domain roles are assigned separately within a module context."
}

{
 "term": "intended_domain_role",
 "definition": "An advisory field set during SLM command normalisation when the user requests a domain-specific role (e.g. 'student').  The system role is set to 'user' and the original domain role name is preserved in this field for downstream domain-role assignment."
}

